// friday13.cs — Find earliest Friday the 13th and count them in a 400-year cycle

// Find the earliest Friday the 13th starting from 0001-01-01 (proleptic Gregorian)
var date = new DateOnly(1, 1, 13); // start checking the 13th of each month
DateOnly? earliest = null;

while (date.Year == 1)
{
    if (date.DayOfWeek == DayOfWeek.Friday)
    {
        earliest = date;
        break;
    }
    date = date.AddMonths(1);
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count Friday the 13ths in a full 400-year Gregorian cycle (years 1–400)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// Bonus: distribution by day-of-week for the 13th
Console.WriteLine("\nDay-of-week distribution for the 13th (400-year cycle):");
var counts = new int[7];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        counts[(int)d.DayOfWeek]++;
    }
}

foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10}: {counts[(int)dow]}");

